noncompliant_example:
class A {
    static final B B_REF = B.INSTANCE;
}
class B {
    static final B INSTANCE = new B();
    B() {
        System.out.println(A.B_REF);
    }
}

compliant_example:
class Registry {
    private static final Registry INSTANCE = new Registry();
    static Registry getInstance() { return INSTANCE; }
}
class Service {
    private final Registry registry = Registry.getInstance();
}
